import{_ as e,o as t,c as r,a2 as n}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"基金常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/fund-faq.md","filePath":"zh-CN/funds-and-wealth/funds/fund-faq.md"}'),o={name:"funds-and-wealth/funds/fund-faq.md"};function l(d,a,s,i,h,u){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="基金常见问题" tabindex="-1">基金常见问题 <a class="header-anchor" href="#基金常见问题" aria-label="Permalink to &quot;基金常见问题&quot;">​</a></h1><p>基金分红、交易截止时间、融资购买限制及基金持仓相关常见问题。</p><h3 id="分红是现金还是份额" tabindex="-1">分红是现金还是份额？ <a class="header-anchor" href="#分红是现金还是份额" aria-label="Permalink to &quot;分红是现金还是份额？&quot;">​</a></h3><p>基金分红统一以<strong>份额</strong>形式发放。无论账户设置的是现金分红还是再投资，实际均以基金份额的方式分配。</p><h3 id="基金交易的截止时间是几点" tabindex="-1">基金交易的截止时间是几点？ <a class="header-anchor" href="#基金交易的截止时间是几点" aria-label="Permalink to &quot;基金交易的截止时间是几点？&quot;">​</a></h3><ul><li>普通基金（股票型、债券型、商品型、平衡型）：每日 <strong>12:00（北京时间）</strong></li><li>货币基金：每日 <strong>09:05（北京时间）</strong></li></ul><p>截止时间前提交按当日净值处理，截止时间后提交顺延至下一交易日。</p><h3 id="可以用融资资金买基金吗" tabindex="-1">可以用融资资金买基金吗？ <a class="header-anchor" href="#可以用融资资金买基金吗" aria-label="Permalink to &quot;可以用融资资金买基金吗？&quot;">​</a></h3><p>不支持。融资账户资金不可用于购买基金，只能使用账户中的自有资金。</p><h3 id="卖出多只基金时-赎回顺序是什么" tabindex="-1">卖出多只基金时，赎回顺序是什么？ <a class="header-anchor" href="#卖出多只基金时-赎回顺序是什么" aria-label="Permalink to &quot;卖出多只基金时，赎回顺序是什么？&quot;">​</a></h3><p>系统按照<strong>先买入先赎回</strong>的原则处理，即先买入的份额优先被赎回。</p><h3 id="卖出后资金什么时候到账" tabindex="-1">卖出后资金什么时候到账？ <a class="header-anchor" href="#卖出后资金什么时候到账" aria-label="Permalink to &quot;卖出后资金什么时候到账？&quot;">​</a></h3><p>普通基金卖出后，资金通常在 T+3 日确认净值后的 <strong>7 个交易日内</strong>到账。具体到账时间以实际为准。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth">基金与理财</a></li></ul>',15)])])}const p=e(o,[["render",l]]);export{c as __pageData,p as default};
